  ('colonel-7fec267e-moex-00034', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於地方制度法上權限爭議與規範審查，下列敘述何者正確？', '["地方自治條例規範電子遊戲場業營業場所與國民小學之距離，不得逾越 中央法規之標準", "食品安全衛生管理法上動物殘留用藥安全容許量之管制標準，地方得訂 定較中央更嚴格之規範", "上下級地方自治團體間之權限爭議，應聲請憲法法庭為宣告違憲之判決", "自治法規被函告無效，地方自治團體經確定終局裁判，得聲請憲法法庭 為宣告違憲之判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
