  ('colonel-7fec267e-moex-00036', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '下列行為發生爭議，何者應向行政法院提起救濟？', '["行政機關為新興建之辦公大樓添購相關設備", "公立醫院向民間廠商採購醫療器材之給付", "台灣自來水公司向自來水用戶收取水費", "衛生福利部中央健康保險署與醫事服務機構簽訂之特約履行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00037', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於公務人員之懲戒與懲處，下列敘述何者正確？', '["懲戒權具有司法權的性質", "懲處的法律依據為公務員懲戒法", "懲戒有功過相抵制度", "懲處不得先行停職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00038', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於公用地役關係之敘述，下列何者錯誤？', '["既成道路之土地所有權，縱未移轉登記而仍為私人所有，私人亦不得於 道路上起造任何建築物", "私人土地長期供自然排水使用，且經歷年代久遠未曾中斷，一般人無復 記憶其確實使用起點，得認其已具公用地役關係", "主管機關於甲所有之既成道路上劃設停車格收取停車費，甲得向主管機 關請求返還所收取停車費之公法上不當得利", "既成道路喪失其原有功能時，主管機關得以對物之一般處分予以廢止"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00039', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於法規命令之效力，下列敘述何者錯誤？', '["法規命令牴觸上級機關之命令，無效", "法規命令無法律授權而限制人民自由權利，無效", "法規命令之一部分無效者，其他部分原則上仍為有效", "主管機關訂定之法規命令，依法應經其他機關核准，如未經核准者，原 則上仍為有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00040', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '依行政程序法規定，有關法規命令之訂定程序，下列敘述何者正確？', '["人民或團體亦得提議訂定法規命令，但須同時提出具體之草案，以達到 人民推動行政立法之目的", "人民提議訂定之法規命令，若非屬於行政機關之職權，則無需進一步處置", "行政機關擬訂法規命令時，應於機關網站事先公告周知", "法規命令之訂定，行政機關得依職權舉行聽證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00041', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政處分之分類，下列敘述何者錯誤？', '["下命處分係課予相對人作為、不作為或容忍義務之處分", "形成處分係設定、變更或消滅具體法律關係、權利、資格或法律地位之 處分", "暫時性行政處分係附有期限之行政處分", "確認處分包括對法律關係存否之確認"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00042', 'colonel-7fec267e', 'colonel-7fec267e-moex-114-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '依行政程序法規定，有關禁止公務員與當事人程序外接觸之敘述，下列何 者錯誤？', '["公務員因職務上必要而為程序外接觸，並非法律所禁止之行為", "公務員與當事人為程序外接觸時所使用之書面文件，應對社會大眾公開", "如與當事人以電話聯絡，須作成書面紀錄，且將接觸對象、時間、地點 及內容清楚記載", "其他當事人如對公務員程序外接觸有疑義，不得立即提出救濟，僅得對 實體決定聲明不服時一併提出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL)
